const errors = [];
for (const field of ['run_id', 'task_id', 'goal', 'criteria', 'iteration', 'instruction', 'status']) {
  if ($json[field] === undefined || $json[field] === null || $json[field] === '') {
    errors.push(`${field} is required`);
  }
}
if (!Array.isArray($json.criteria) || $json.criteria.length === 0) {
  errors.push('criteria must contain at least one item');
}
return [{ json: { ...$json, validation_errors: errors } }];

const input = $json;

const context =
  input.context && typeof input.context === 'object'
    ? input.context
    : {};

const requestedMode =
  typeof context.provider_mode === 'string' && context.provider_mode.trim()
    ? context.provider_mode.trim()
    : typeof context.agent_mode === 'string' && context.agent_mode.trim()
      ? context.agent_mode.trim()
      : typeof input.provider_mode === 'string' && input.provider_mode.trim()
        ? input.provider_mode.trim()
        : typeof input.agent_mode === 'string' && input.agent_mode.trim()
          ? input.agent_mode.trim()
          : 'mock';

const supportedModes = new Set(['mock', 'dry-run', 'real-readonly']);
const resolvedMode = supportedModes.has(requestedMode)
  ? requestedMode
  : 'mock';

const modeWarnings = supportedModes.has(requestedMode)
  ? []
  : ['unknown provider mode fallback to mock'];

return [
  {
    json: {
      ...input,
      context: {
        ...context,
        agent_mode: resolvedMode,
        provider_mode: resolvedMode,
      },
      prompt_reference: 'src/prompts/subagent_prompt.md',
      prompt_contract: {
        output: 'result.schema.json',
        format: 'json_only',
      },
      agent_mode: resolvedMode,
      provider_mode: resolvedMode,
      requested_provider_mode: requestedMode,
      mode_warnings: modeWarnings,
    },
  },
];

if (($json.validation_errors || []).length > 0) {
  return [{
    json: {
      run_id: $json.run_id || 'unknown',
      task_id: $json.task_id || 'unknown',
      status: 'failed',
      summary: 'Task validation failed before execution.',
      artifacts: [],
      known_issues: $json.validation_errors,
      evidence: ($json.criteria || ['task payload']).map((criterion) => ({
        criterion,
        status: 'fail',
        detail: 'Executor could not run because the task payload was invalid.'
      })),
      next_action_suggestion: 'Fix the task payload and retry.',
      error: {
        code: 'TASK_VALIDATION_FAILED',
        message: $json.validation_errors.join('; ')
      }
    }
  }];
}

const evidence = ($json.criteria || []).map((criterion, index) => ({
  criterion,
  status: index < 2 ? 'pass' : 'fail',
  detail: index < 2
    ? `Mock executor produced evidence for criterion ${index + 1}.`
    : `Mock executor intentionally leaves criterion ${index + 1} unresolved.`
}));

return [{
  json: {
    run_id: $json.run_id,
    task_id: $json.task_id,
    status: evidence.every((item) => item.status === 'pass') ? 'completed' : 'partial',
    summary: 'Mock executor completed one bounded task iteration.',
    artifacts: ['docs/WORKFLOW_DESIGN.md'],
    known_issues: evidence.filter((item) => item.status !== 'pass').map((item) => item.detail),
    evidence,
    next_action_suggestion: 'Run Criteria Checker to assess whether another iteration is required.',
    error: null
  }
}];

const input = $json || {};
const agentResult =
  input.agent_result && typeof input.agent_result === 'object'
    ? input.agent_result
    : {};

const artifacts = Array.isArray(agentResult.artifacts)
  ? agentResult.artifacts
  : [];

const knownIssues = Array.isArray(agentResult.known_issues)
  ? agentResult.known_issues
  : [];

const criteria = Array.isArray(input.criteria)
  ? input.criteria
  : [];

return [
  {
    json: {
      ...input,
      execution_log: {
        logged_at: new Date().toISOString(),
        summary: agentResult.summary || 'Agent execution completed.',
        artifact_count: artifacts.length,
        issue_count: knownIssues.length,
        criteria_count: criteria.length,
        provider_mode:
          agentResult.provider && agentResult.provider.mode
            ? agentResult.provider.mode
            : input.provider_mode || input.agent_mode || 'mock',
      },
    },
  },
];

const input = $json || {};

const context =
  input.context && typeof input.context === 'object'
    ? input.context
    : {};

const criteria = Array.isArray(input.criteria)
  ? input.criteria
  : [];

const runId =
  input.run_id ||
  `gd_${Date.now()}`;

const taskId =
  input.task_id ||
  `task_${Date.now()}`;

const riskLevel =
  input.risk_level ||
  context.risk_level ||
  'low';

const evidence = criteria.map((criterion) => ({
  criterion,
  status: 'unknown',
  detail: 'Dry-run generated a plan but did not execute real work.',
}));

const intendedActions = [
  'Review the goal and acceptance criteria.',
  'Generate a bounded execution plan.',
  'Identify required artifacts and expected evidence.',
  'Request human approval before any real provider execution.',
];

return [
  {
    json: {
      ...input,

      run_id: runId,
      task_id: taskId,
      status: 'needs_review',

      summary: 'Dry-run plan generated. No real action was executed.',
      artifacts: [],
      known_issues: [],
      evidence,

      dry_run_plan: {
        goal: input.goal || '',
        intended_actions: intendedActions,
        risk_summary: `Dry-run only. No real action was executed. Current risk level: ${riskLevel}.`,
        requires_human_approval_before_real_run: true,
      },

      provider: {
        mode: 'dry-run',
        name: 'dry-run-provider',
        model: null,
        request_id: null,
        latency_ms: 0,
      },

      safety: {
        risk_level: riskLevel,
        requires_human_approval: true,
        approved: false,
        blocked_reason: 'dry-run mode does not execute real actions',
      },
    },
  },
];

const input = $json || {};

const context =
  input.context && typeof input.context === 'object'
    ? input.context
    : {};

const criteria = Array.isArray(input.criteria)
  ? input.criteria
  : [];

const runId =
  input.run_id ||
  `gd_${Date.now()}`;

const taskId =
  input.task_id ||
  `task_${Date.now()}`;

const riskLevel =
  input.risk_level ||
  context.risk_level ||
  'low';

const evidence = criteria.map((criterion) => ({
  criterion,
  status: 'unknown',
  detail: 'Real-readonly stub generated analysis but did not execute real work.',
}));

const intendedActions = [
  'Review the goal and acceptance criteria.',
  'Generate a read-only implementation plan.',
  'Identify expected evidence without executing changes.',
  'Request human approval before any real execution mode.',
];

return [
  {
    json: {
      ...input,

      run_id: runId,
      task_id: taskId,
      status: 'needs_review',

      summary: 'Real-readonly provider stub generated a review plan. No real action was executed.',
      artifacts: [],
      known_issues: [],
      evidence,
      intended_actions: intendedActions,
      risk_summary: `Real-readonly stub only. No real action was executed. Current risk level: ${riskLevel}.`,

      provider: {
        mode: 'real-readonly',
        name: 'real-readonly-stub',
        model: null,
        request_id: null,
        latency_ms: 0,
      },

      safety: {
        risk_level: riskLevel,
        requires_human_approval: true,
        approved: false,
        blocked_reason: 'real-readonly mode does not execute real actions',
      },
    },
  },
];

const adapterOutput = $json || {};

let taskInput = {};
try {
  taskInput = $('Prompt Builder').item.json || {};
} catch (error) {
  taskInput = {};
}

const context =
  taskInput.context && typeof taskInput.context === 'object'
    ? taskInput.context
    : adapterOutput.context && typeof adapterOutput.context === 'object'
      ? adapterOutput.context
      : {};

const runId =
  taskInput.run_id ||
  adapterOutput.run_id ||
  'gd_' + Date.now();

const taskId =
  taskInput.task_id ||
  adapterOutput.task_id ||
  'task_' + Date.now();

const goal =
  typeof taskInput.goal === 'string'
    ? taskInput.goal
    : typeof adapterOutput.goal === 'string'
      ? adapterOutput.goal
      : '';

const criteria = Array.isArray(taskInput.criteria)
  ? taskInput.criteria
  : Array.isArray(adapterOutput.criteria)
    ? adapterOutput.criteria
    : [];

const iteration =
  Number.isInteger(taskInput.iteration)
    ? taskInput.iteration
    : Number.isInteger(adapterOutput.iteration)
      ? adapterOutput.iteration
      : 1;

const artifacts = Array.isArray(adapterOutput.artifacts)
  ? adapterOutput.artifacts
  : [];

const knownIssues = Array.isArray(adapterOutput.known_issues)
  ? adapterOutput.known_issues
  : [];

const evidence = Array.isArray(adapterOutput.evidence)
  ? adapterOutput.evidence
  : [];

const resolvedMode =
  (adapterOutput.provider && adapterOutput.provider.mode) ||
  taskInput.provider_mode ||
  taskInput.agent_mode ||
  'mock';

const provider =
  adapterOutput.provider && typeof adapterOutput.provider === 'object'
    ? adapterOutput.provider
    : {
        mode: resolvedMode,
        name: resolvedMode === 'mock' ? 'mock-agent-adapter' : 'unknown-provider',
        model: null,
        request_id: null,
        latency_ms: 0,
      };

const riskLevel =
  adapterOutput.safety && adapterOutput.safety.risk_level
    ? adapterOutput.safety.risk_level
    : taskInput.risk_level || context.risk_level || 'low';

const safety =
  adapterOutput.safety && typeof adapterOutput.safety === 'object'
    ? adapterOutput.safety
    : {
        risk_level: riskLevel,
        requires_human_approval: resolvedMode !== 'mock',
        approved: resolvedMode === 'mock' ? true : Boolean(taskInput.human_approved),
        blocked_reason: resolvedMode === 'mock' ? null : 'provider mode requires explicit approval before real execution',
      };

const dryRunPlan =
  adapterOutput.dry_run_plan && typeof adapterOutput.dry_run_plan === 'object'
    ? adapterOutput.dry_run_plan
    : null;

const intendedActions = Array.isArray(adapterOutput.intended_actions)
  ? adapterOutput.intended_actions
  : null;

const riskSummary =
  typeof adapterOutput.risk_summary === 'string' && adapterOutput.risk_summary.trim()
    ? adapterOutput.risk_summary
    : null;

const modeWarnings = Array.isArray(adapterOutput.mode_warnings)
  ? adapterOutput.mode_warnings
  : Array.isArray(taskInput.mode_warnings)
    ? taskInput.mode_warnings
    : [];

return [
  {
    json: {
      ...taskInput,
      ...adapterOutput,
      run_id: runId,
      task_id: taskId,
      goal,
      criteria,
      context,
      iteration,
      agent_result: {
        run_id: runId,
        task_id: taskId,
        status: adapterOutput.status || 'failed',
        summary: adapterOutput.summary || 'Agent execution returned no summary.',
        artifacts,
        known_issues: knownIssues,
        evidence,
        provider,
        safety,
        ...(dryRunPlan ? { dry_run_plan: dryRunPlan } : {}),
        ...(intendedActions ? { intended_actions: intendedActions } : {}),
        ...(riskSummary ? { risk_summary: riskSummary } : {}),
        ...(modeWarnings.length > 0 ? { mode_warnings: modeWarnings } : {}),
      },
    },
  },
];
